#!/usr/bin/env python3
"""All backend fixes. Run from: /workspaces/dream-os"""
import os
ROOT = os.path.dirname(os.path.abspath(__file__))
def write(rel, content):
    path = os.path.join(ROOT, rel)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w") as f: f.write(content)
    print(f"  wrote  {rel}")
FILES = {'src/api/admin/invites.js': "// src/api/admin/invites.js\n// Admin invite code management — generate, list, delete + WhatsApp links.\n'use strict';\n\nconst express      = require('express');\nconst router       = express.Router();\nconst requireAdmin = require('./requireAdmin');\nconst asyncHandler = require('../../lib/asyncHandler');\nconst { ok: okRes, err: errRes } = require('../../lib/response');\nconst crypto       = require('crypto');\n\nconst ALPHABET = 'ABCDEFGHJKMNPQRSTUVWXYZ23456789';\n\nfunction generateCode() {\n  let code = '';\n  const bytes = crypto.randomBytes(8);\n  for (let i = 0; i < 8; i++) code += ALPHABET[bytes[i] % ALPHABET.length];\n  return code;\n}\n\nconst VENDOR_WA_NUMBER = process.env.TDW_WA_NUMBER   || '917982159047';\nconst COUPLE_WA_NUMBER = process.env.BRIDE_WA_NUMBER || '14787788550';\n\n// GET /whatsapp-links\nrouter.get('/whatsapp-links', requireAdmin, asyncHandler(async (req, res) => {\n  return okRes(res, {\n    vendor: `https://wa.me/${VENDOR_WA_NUMBER}`,\n    couple: `https://wa.me/${COUPLE_WA_NUMBER}`,\n    note:   'Share these links. When someone messages, the agent onboards them automatically.',\n  });\n}));\n\n// GET /\nrouter.get('/', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { data, error } = await supabase\n    .from('invite_codes')\n    .select(`code, kind, tier, intended_phone, notes, created_by,\n             created_at, consumed_at, consumed_by_user_id,\n             users:consumed_by_user_id(phone)`)\n    .order('created_at', { ascending: false });\n  if (error) return errRes(res, 500, error.message);\n\n  const invites = (data || []).map(r => ({\n    code:              r.code,\n    kind:              r.kind,\n    tier:              r.tier || null,\n    intended_phone:    r.intended_phone || null,\n    notes:             r.notes || null,\n    created_by:        r.created_by || null,\n    created_at:        r.created_at,\n    consumed_at:       r.consumed_at || null,\n    consumed_by_phone: r.users?.phone || null,\n  }));\n\n  return okRes(res, { invites, total: invites.length });\n}));\n\n// POST /generate\n// When phone is provided, ALSO creates the users + vendor/couple row immediately\n// so send-otp works the moment they enter the code on the web.\nrouter.post('/generate', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { kind, tier, intended_phone, name, notes, count = 1 } = req.body;\n\n  if (!kind || !['dreamer', 'maker'].includes(kind))\n    return errRes(res, 400, 'kind is required: dreamer or maker.');\n\n  // If phone is provided, it is mandatory to also provide a name.\n  // We create the users + vendor/couple row right now so web OTP works immediately.\n  if (intended_phone) {\n    if (!name || !name.trim())\n      return errRes(res, 400, 'name is required when phone is provided.');\n\n    const cleanPhone = intended_phone.trim();\n    const cleanName  = name.trim();\n\n    // Check if user already exists\n    const { data: existingUser } = await supabase\n      .from('users').select('id').eq('phone', cleanPhone).maybeSingle();\n\n    if (!existingUser) {\n      // Create user + vendor/couple row via the same RPCs the old HTML admin used\n      const rpc = kind === 'maker' ? 'invite_vendor' : 'invite_couple';\n      const rpcParams = kind === 'maker'\n        ? { p_phone: cleanPhone, p_name: cleanName }\n        : { p_phone: cleanPhone, p_name: cleanName, p_pronouns: 'they/them' };\n\n      const { error: rpcErr } = await supabase.rpc(rpc, rpcParams);\n      if (rpcErr) return errRes(res, 400, `Could not create account: ${rpcErr.message}`);\n\n      // Set tier if provided\n      if (tier && kind === 'maker') {\n        const { data: userRow } = await supabase.from('users').select('id').eq('phone', cleanPhone).maybeSingle();\n        if (userRow) await supabase.from('vendors').update({ tier }).eq('user_id', userRow.id);\n      }\n\n      console.log(`[admin:invites] pre-created ${kind} account for ${cleanPhone}`);\n    }\n  }\n\n  // Generate exactly 1 code when phone is bound, up to 50 otherwise\n  const qty  = intended_phone ? 1 : Math.min(Math.max(1, parseInt(count) || 1), 50);\n  const rows = Array.from({ length: qty }, () => ({\n    code:           generateCode(),\n    kind,\n    tier:           tier || null,\n    intended_phone: intended_phone || null,\n    notes:          notes || null,\n    created_by:     'admin',\n  }));\n\n  const { data, error } = await supabase.from('invite_codes').insert(rows).select('code, kind, tier, intended_phone');\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { codes: data, total: data.length });\n}));\n\n// DELETE /:code\nrouter.delete('/:code', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const code     = req.params.code.toUpperCase();\n  const { data: row } = await supabase.from('invite_codes').select('code, consumed_at').eq('code', code).single();\n  if (!row) return errRes(res, 404, 'Invite code not found.');\n  if (row.consumed_at) return errRes(res, 409, 'Cannot delete a consumed invite code.');\n  const { error } = await supabase.from('invite_codes').delete().eq('code', code);\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { deleted: true });\n}));\n\nmodule.exports = router;\n", 'src/api/vendor/auth.js': '// src/api/vendor/auth.js\n// Vendor PWA auth endpoints — P2-4 clean build.\n// Mounted at /api/v2/vendor/auth via src/api/router.js\n//\n// ENDPOINTS\n//   POST /send-otp     — send WhatsApp OTP to vendor phone\n//   POST /verify-otp   — verify OTP, mint JWT, return tokens\n//   POST /set-pin      — bcrypt PIN, store in vendors.pin_hash\n//   POST /pin-login    — verify PIN, mint JWT, return tokens\n//   POST /forgot-pin   — send reset OTP (purpose=reset)\n//\n// SESSION CONTRACT\n//   verify-otp and pin-login return { access_token, refresh_token }.\n//   PWA stores in localStorage. All protected endpoints require:\n//   Authorization: Bearer <access_token>\n//\n// MINT PATTERN (lazy auth.users backfill)\n//   1. createUser — idempotent, pins users.id as auth.users UUID\n//   2. updateUserById — pins stable internal email (no email dispatched)\n//   3. generateLink magiclink — returns hashed_token (no email dispatched)\n//   4. verifyOtp token_hash — exchanges token for real JWT session\n\n\'use strict\';\n\nconst express = require(\'express\');\nconst router  = express.Router();\nconst bcrypt  = require(\'bcryptjs\');\nconst twilio  = require(\'twilio\');\n\nconst BCRYPT_ROUNDS    = 10;\nconst OTP_TTL_MS       = 5 * 60 * 1000;\nconst PIN_RE           = /^\\d{4}$/;\nconst PHONE_RE         = /^\\+[0-9]{8,15}$/;\nconst LOCKOUT_ATTEMPTS = 5;\nconst LOCKOUT_MS       = 15 * 60 * 1000;\n\nconst VENDOR_WA = process.env.TDW_WA_NUMBER\n  ? `+${process.env.TDW_WA_NUMBER}`\n  : \'+917982159047\';\n\nfunction getTwilio() {\n  return twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);\n}\n\nfunction generateOtp() {\n  return String(Math.floor(Math.random() * 1_000_000)).padStart(6, \'0\');\n}\n\n// ---------------------------------------------------------------------------\n// mintSession\n// Lazy auth.users backfill + JWT session mint.\n// Called after OTP verify or PIN verify — phone already proved at that point.\n// ---------------------------------------------------------------------------\nasync function mintSession(supabase, userId) {\n  // Step 1 — create auth.users row pinned to our users.id UUID.\n  // Idempotent: 422 / "already registered" means row exists, continue.\n  const { data: created, error: createErr } = await supabase.auth.admin.createUser({\n    id:            userId,\n    email:         `vendor-${userId}@internal.dreamai.app`,\n    email_confirm: true,\n  });\n\n  let authId = userId;\n  if (createErr) {\n    const msg = createErr.message || \'\';\n    if (!msg.includes(\'already registered\') && !msg.includes(\'already been registered\') && createErr.status !== 422) {\n      throw new Error(`auth.users create failed: ${msg}`);\n    }\n    // Already exists — look it up\n    const { data: existing, error: lookupErr } = await supabase.auth.admin.getUserById(userId);\n    if (lookupErr || !existing?.user) {\n      throw new Error(`auth.users lookup failed: ${lookupErr?.message || \'no user\'}`);\n    }\n    authId = existing.user.id;\n  } else {\n    authId = created.user.id;\n  }\n\n  // Step 2 — pin a stable internal email (required by generateLink).\n  // Admin update does not dispatch any email.\n  const internalEmail = `vendor-${authId}@internal.dreamai.app`;\n  const { error: updateErr } = await supabase.auth.admin.updateUserById(authId, {\n    email:         internalEmail,\n    email_confirm: true,\n  });\n  if (updateErr) throw new Error(`auth.users email pin failed: ${updateErr.message}`);\n\n  // Step 3 — generate magic-link token server-side. No email dispatched.\n  const { data: linkData, error: linkErr } = await supabase.auth.admin.generateLink({\n    type:  \'magiclink\',\n    email: internalEmail,\n  });\n  if (linkErr) throw new Error(`generateLink failed: ${linkErr.message}`);\n\n  // Step 4 — exchange hashed_token for real JWT session.\n  const { data: sessionData, error: sessionErr } = await supabase.auth.verifyOtp({\n    token_hash: linkData.properties.hashed_token,\n    type:       \'email\',\n  });\n  if (sessionErr) throw new Error(`verifyOtp failed: ${sessionErr.message}`);\n\n  return {\n    access_token:  sessionData.session.access_token,\n    refresh_token: sessionData.session.refresh_token,\n  };\n}\n\n// ---------------------------------------------------------------------------\n// POST /send-otp\n// ---------------------------------------------------------------------------\nrouter.post(\'/send-otp\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone } = req.body;\n\n  if (!phone || !PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n  const cleanPhone = phone.trim();\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) {\n    return res.status(404).json({\n      error:  \'No account found for this number. Please check your invite.\',\n      reason: \'phone_not_found\',\n    });\n  }\n\n  const { data: vendorRow } = await supabase\n    .from(\'vendors\').select(\'id\').eq(\'user_id\', userRow.id).maybeSingle();\n  if (!vendorRow) {\n    return res.status(403).json({\n      error:  \'This number is registered as a Dreamer account, not a Maker.\',\n      reason: \'wrong_role\',\n    });\n  }\n\n  const otp     = generateOtp();\n  const otpHash = await bcrypt.hash(otp, BCRYPT_ROUNDS);\n  const expires = new Date(Date.now() + OTP_TTL_MS).toISOString();\n\n  const { error: upsertErr } = await supabase.from(\'otp_sessions\').upsert(\n    { phone: cleanPhone, otp_hash: otpHash, purpose: \'login\', expires_at: expires, created_at: new Date().toISOString() },\n    { onConflict: \'phone\' }\n  );\n  if (upsertErr) {\n    console.error(\'[vendor:send-otp] upsert error:\', upsertErr.message);\n    return res.status(500).json({ error: \'Something went wrong. Please try again.\' });\n  }\n\n  try {\n    await getTwilio().messages.create({\n      from: `whatsapp:${VENDOR_WA}`,\n      to:   `whatsapp:${cleanPhone}`,\n      body: `Your DreamAI login code is: ${otp}. Valid for 5 minutes. Do not share this code.`,\n    });\n  } catch (err) {\n    console.error(\'[vendor:send-otp] twilio error:\', err.message);\n    await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n    return res.status(500).json({ error: \'Could not send WhatsApp message. Please try again.\' });\n  }\n\n  console.log(`[vendor:send-otp] sent to ${cleanPhone}`);\n  return res.json({ ok: true });\n});\n\n// ---------------------------------------------------------------------------\n// POST /forgot-pin\n// ---------------------------------------------------------------------------\nrouter.post(\'/forgot-pin\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone } = req.body;\n\n  if (!phone || !PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n  const cleanPhone = phone.trim();\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) {\n    return res.status(404).json({ error: \'No account found for this number.\', reason: \'phone_not_found\' });\n  }\n\n  const { data: vendorRow } = await supabase\n    .from(\'vendors\').select(\'id\').eq(\'user_id\', userRow.id).maybeSingle();\n  if (!vendorRow) {\n    return res.status(403).json({ error: \'This number is not a Maker account.\', reason: \'wrong_role\' });\n  }\n\n  const otp     = generateOtp();\n  const otpHash = await bcrypt.hash(otp, BCRYPT_ROUNDS);\n  const expires = new Date(Date.now() + OTP_TTL_MS).toISOString();\n\n  const { error: upsertErr } = await supabase.from(\'otp_sessions\').upsert(\n    { phone: cleanPhone, otp_hash: otpHash, purpose: \'reset\', expires_at: expires, created_at: new Date().toISOString() },\n    { onConflict: \'phone\' }\n  );\n  if (upsertErr) {\n    console.error(\'[vendor:forgot-pin] upsert error:\', upsertErr.message);\n    return res.status(500).json({ error: \'Something went wrong. Please try again.\' });\n  }\n\n  try {\n    await getTwilio().messages.create({\n      from: `whatsapp:${VENDOR_WA}`,\n      to:   `whatsapp:${cleanPhone}`,\n      body: `Your DreamAI PIN reset code is: ${otp}. Valid for 5 minutes. Do not share this code.`,\n    });\n  } catch (err) {\n    console.error(\'[vendor:forgot-pin] twilio error:\', err.message);\n    await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n    return res.status(500).json({ error: \'Could not send WhatsApp message. Please try again.\' });\n  }\n\n  console.log(`[vendor:forgot-pin] reset OTP sent to ${cleanPhone}`);\n  return res.json({ ok: true });\n});\n\n// ---------------------------------------------------------------------------\n// POST /verify-otp\n// Body:    { phone, otp, purpose }\n// Returns: { ok, user_id, vendor_id, pin_set, access_token, refresh_token }\n// ---------------------------------------------------------------------------\nrouter.post(\'/verify-otp\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone, otp, purpose } = req.body;\n\n  if (!phone || !otp || !purpose) {\n    return res.status(400).json({ error: \'phone, otp and purpose are required.\' });\n  }\n  if (![\'login\', \'reset\'].includes(purpose)) {\n    return res.status(400).json({ error: \'purpose must be login or reset.\' });\n  }\n  if (!PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n\n  const cleanPhone = phone.trim();\n  const cleanOtp   = String(otp).trim();\n\n  const { data: otpRow } = await supabase\n    .from(\'otp_sessions\').select(\'otp_hash, purpose, expires_at\')\n    .eq(\'phone\', cleanPhone).maybeSingle();\n\n  if (!otpRow) {\n    return res.status(400).json({ error: \'No OTP found. Please request a new one.\', reason: \'otp_not_found\' });\n  }\n  if (new Date(otpRow.expires_at) < new Date()) {\n    await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n    return res.status(400).json({ error: \'OTP has expired. Please request a new one.\', reason: \'otp_expired\' });\n  }\n  if (otpRow.purpose !== purpose) {\n    return res.status(400).json({ error: \'OTP purpose mismatch.\', reason: \'otp_purpose_mismatch\' });\n  }\n\n  const valid = await bcrypt.compare(cleanOtp, otpRow.otp_hash);\n  if (!valid) {\n    return res.status(400).json({ error: \'Incorrect code. Please try again.\', reason: \'otp_invalid\' });\n  }\n\n  await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) return res.status(500).json({ error: \'Account not found after OTP verification.\' });\n\n  const { data: vendorRow } = await supabase\n    .from(\'vendors\').select(\'id, pin_hash, pin_failed_attempts, pin_locked_until, business_name, category, tier, routing_handle, users!inner(name)\')\n    .eq(\'user_id\', userRow.id).maybeSingle();\n  if (!vendorRow) return res.status(500).json({ error: \'Vendor record not found after OTP verification.\' });\n\n  if (purpose === \'reset\' && (vendorRow.pin_failed_attempts > 0 || vendorRow.pin_locked_until)) {\n    await supabase.from(\'vendors\')\n      .update({ pin_failed_attempts: 0, pin_locked_until: null })\n      .eq(\'id\', vendorRow.id);\n  }\n\n  let tokens;\n  try {\n    tokens = await mintSession(supabase, userRow.id);\n  } catch (err) {\n    console.error(\'[vendor:verify-otp] mint error:\', err.message);\n    return res.status(500).json({ error: \'Could not create session. Please try again.\' });\n  }\n\n  const pinSet = !!vendorRow.pin_hash;\n  console.log(`[vendor:verify-otp] ok phone=${cleanPhone} purpose=${purpose} pin_set=${pinSet}`);\n  const vendorName = vendorRow.business_name || vendorRow.users?.name || null;\n  return res.json({\n    ok:            true,\n    user_id:       userRow.id,\n    vendor_id:     vendorRow.id,\n    pin_set:       pinSet,\n    name:          vendorName,\n    category:      vendorRow.category || null,\n    tier:          vendorRow.tier || null,\n    routing_handle: vendorRow.routing_handle || null,\n    access_token:  tokens.access_token,\n    refresh_token: tokens.refresh_token,\n  });\n});\n\n// ---------------------------------------------------------------------------\n// POST /set-pin\n// Body: { vendor_id, pin }\n// No auth — called immediately after verify-otp (phone already proved).\n// ---------------------------------------------------------------------------\nrouter.post(\'/set-pin\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { vendor_id, pin } = req.body;\n\n  if (!vendor_id || !pin) {\n    return res.status(400).json({ error: \'vendor_id and pin are required.\' });\n  }\n  if (!PIN_RE.test(pin)) {\n    return res.status(400).json({ error: \'PIN must be exactly 4 digits.\' });\n  }\n\n  const pinHash = await bcrypt.hash(pin, BCRYPT_ROUNDS);\n  const { error } = await supabase.from(\'vendors\')\n    .update({ pin_hash: pinHash, pin_failed_attempts: 0, pin_locked_until: null })\n    .eq(\'id\', vendor_id);\n\n  if (error) {\n    console.error(\'[vendor:set-pin] error:\', error.message);\n    return res.status(500).json({ error: \'Something went wrong. Please try again.\' });\n  }\n\n  console.log(`[vendor:set-pin] PIN set vendor_id=${vendor_id}`);\n  return res.json({ ok: true });\n});\n\n// ---------------------------------------------------------------------------\n// POST /pin-login\n// Body:    { phone, pin }\n// Returns: { ok, user_id, vendor_id, access_token, refresh_token }\n// ---------------------------------------------------------------------------\nrouter.post(\'/pin-login\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone, pin } = req.body;\n\n  if (!phone || !pin) {\n    return res.status(400).json({ error: \'phone and pin are required.\' });\n  }\n  if (!PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n  if (!PIN_RE.test(pin)) {\n    return res.status(400).json({ error: \'PIN must be exactly 4 digits.\' });\n  }\n\n  const cleanPhone = phone.trim();\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) {\n    return res.status(404).json({ error: \'No account found for this number.\', reason: \'phone_not_found\' });\n  }\n\n  const { data: vendorRow } = await supabase\n    .from(\'vendors\').select(\'id, pin_hash, pin_failed_attempts, pin_locked_until\')\n    .eq(\'user_id\', userRow.id).maybeSingle();\n  if (!vendorRow) {\n    return res.status(403).json({ error: \'This number is not a Maker account.\', reason: \'wrong_role\' });\n  }\n  if (!vendorRow.pin_hash) {\n    return res.status(400).json({ error: \'PIN not set yet. Please sign in with OTP first.\', reason: \'pin_not_set\' });\n  }\n\n  if (vendorRow.pin_locked_until && new Date(vendorRow.pin_locked_until) > new Date()) {\n    const mins = Math.ceil((new Date(vendorRow.pin_locked_until) - Date.now()) / 60000);\n    return res.status(429).json({\n      error:        `Too many incorrect attempts. Try again in ${mins} minute${mins === 1 ? \'\' : \'s\'}, or use Forgot PIN.`,\n      reason:       \'pin_locked\',\n      locked_until: vendorRow.pin_locked_until,\n    });\n  }\n\n  const valid = await bcrypt.compare(pin, vendorRow.pin_hash);\n\n  if (!valid) {\n    const attempts = (vendorRow.pin_failed_attempts || 0) + 1;\n    const update   = { pin_failed_attempts: attempts };\n    if (attempts >= LOCKOUT_ATTEMPTS) {\n      update.pin_locked_until    = new Date(Date.now() + LOCKOUT_MS).toISOString();\n      update.pin_failed_attempts = 0;\n    }\n    await supabase.from(\'vendors\').update(update).eq(\'id\', vendorRow.id);\n    const left = LOCKOUT_ATTEMPTS - attempts;\n    console.log(`[vendor:pin-login] wrong PIN phone=${cleanPhone} attempts=${attempts}`);\n    if (attempts >= LOCKOUT_ATTEMPTS) {\n      return res.status(429).json({ error: \'Too many incorrect attempts. Locked out for 15 minutes. Use Forgot PIN.\', reason: \'pin_locked\' });\n    }\n    return res.status(400).json({\n      error:              `Incorrect PIN. ${left} attempt${left === 1 ? \'\' : \'s\'} remaining.`,\n      reason:             \'pin_invalid\',\n      attempts_remaining: left,\n    });\n  }\n\n  await supabase.from(\'vendors\')\n    .update({ pin_failed_attempts: 0, pin_locked_until: null })\n    .eq(\'id\', vendorRow.id);\n\n  let tokens;\n  try {\n    tokens = await mintSession(supabase, userRow.id);\n  } catch (err) {\n    console.error(\'[vendor:pin-login] mint error:\', err.message);\n    return res.status(500).json({ error: \'Could not create session. Please try again.\' });\n  }\n\n  console.log(`[vendor:pin-login] ok phone=${cleanPhone} vendor_id=${vendorRow.id}`);\n  return res.json({\n    ok:            true,\n    user_id:       userRow.id,\n    vendor_id:     vendorRow.id,\n    access_token:  tokens.access_token,\n    refresh_token: tokens.refresh_token,\n  });\n});\n\n// ---------------------------------------------------------------------------\n// POST /refresh\n// Body:    { refresh_token }\n// Returns: { ok, access_token, refresh_token }\n// No requireAuth — this is called precisely when the access_token has expired.\n// ---------------------------------------------------------------------------\nrouter.post(\'/refresh\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { refresh_token } = req.body;\n\n  if (!refresh_token || typeof refresh_token !== \'string\') {\n    return res.status(400).json({ error: \'refresh_token is required.\', reason: \'missing_token\' });\n  }\n\n  try {\n    // Exchange refresh_token for a new session via Supabase\n    const { data, error } = await supabase.auth.refreshSession({ refresh_token });\n\n    if (error || !data?.session) {\n      console.warn(\'[vendor:refresh] refresh failed:\', error?.message || \'no session\');\n      return res.status(401).json({\n        error:  \'Session expired. Please log in again.\',\n        reason: \'refresh_failed\',\n      });\n    }\n\n    console.log(\'[vendor:refresh] session refreshed successfully\');\n    return res.json({\n      ok:            true,\n      access_token:  data.session.access_token,\n      refresh_token: data.session.refresh_token,\n    });\n\n  } catch (err) {\n    console.error(\'[vendor:refresh] unexpected error:\', err.message);\n    return res.status(500).json({ error: \'Could not refresh session. Please log in again.\' });\n  }\n});\n\nmodule.exports = router;\n', 'src/api/couple/auth.js': '// src/api/couple/auth.js\n// Vendor PWA auth endpoints — P2-4 clean build.\n// Mounted at /api/v2/couple/auth via src/api/router.js\n//\n// ENDPOINTS\n//   POST /send-otp     — send WhatsApp OTP to couple phone\n//   POST /verify-otp   — verify OTP, mint JWT, return tokens\n//   POST /set-pin      — bcrypt PIN, store in couples.pin_hash\n//   POST /pin-login    — verify PIN, mint JWT, return tokens\n//   POST /forgot-pin   — send reset OTP (purpose=reset)\n//\n// SESSION CONTRACT\n//   verify-otp and pin-login return { access_token, refresh_token }.\n//   PWA stores in localStorage. All protected endpoints require:\n//   Authorization: Bearer <access_token>\n//\n// MINT PATTERN (lazy auth.users backfill)\n//   1. createUser — idempotent, pins users.id as auth.users UUID\n//   2. updateUserById — pins stable internal email (no email dispatched)\n//   3. generateLink magiclink — returns hashed_token (no email dispatched)\n//   4. verifyOtp token_hash — exchanges token for real JWT session\n\n\'use strict\';\n\nconst express = require(\'express\');\nconst router  = express.Router();\nconst bcrypt  = require(\'bcryptjs\');\nconst twilio  = require(\'twilio\');\n\nconst BCRYPT_ROUNDS    = 10;\nconst OTP_TTL_MS       = 5 * 60 * 1000;\nconst PIN_RE           = /^\\d{4}$/;\nconst PHONE_RE         = /^\\+[0-9]{8,15}$/;\nconst LOCKOUT_ATTEMPTS = 5;\nconst LOCKOUT_MS       = 15 * 60 * 1000;\n\nconst BRIDE_WA = process.env.BRIDE_WA_NUMBER\n  ? `+${process.env.BRIDE_WA_NUMBER}`\n  : \'+14787788550\';\n\nfunction getTwilio() {\n  return twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);\n}\n\nfunction generateOtp() {\n  return String(Math.floor(Math.random() * 1_000_000)).padStart(6, \'0\');\n}\n\n// ---------------------------------------------------------------------------\n// mintSession\n// Lazy auth.users backfill + JWT session mint.\n// Called after OTP verify or PIN verify — phone already proved at that point.\n// ---------------------------------------------------------------------------\nasync function mintSession(supabase, userId) {\n  // Step 1 — create auth.users row pinned to our users.id UUID.\n  // Idempotent: 422 / "already registered" means row exists, continue.\n  const { data: created, error: createErr } = await supabase.auth.admin.createUser({\n    id:            userId,\n    email:         `couple-${userId}@internal.dreamai.app`,\n    email_confirm: true,\n  });\n\n  let authId = userId;\n  if (createErr) {\n    const msg = createErr.message || \'\';\n    if (!msg.includes(\'already registered\') && !msg.includes(\'already been registered\') && createErr.status !== 422) {\n      throw new Error(`auth.users create failed: ${msg}`);\n    }\n    // Already exists — look it up\n    const { data: existing, error: lookupErr } = await supabase.auth.admin.getUserById(userId);\n    if (lookupErr || !existing?.user) {\n      throw new Error(`auth.users lookup failed: ${lookupErr?.message || \'no user\'}`);\n    }\n    authId = existing.user.id;\n  } else {\n    authId = created.user.id;\n  }\n\n  // Step 2 — pin a stable internal email (required by generateLink).\n  // Admin update does not dispatch any email.\n  const internalEmail = `couple-${authId}@internal.dreamai.app`;\n  const { error: updateErr } = await supabase.auth.admin.updateUserById(authId, {\n    email:         internalEmail,\n    email_confirm: true,\n  });\n  if (updateErr) throw new Error(`auth.users email pin failed: ${updateErr.message}`);\n\n  // Step 3 — generate magic-link token server-side. No email dispatched.\n  const { data: linkData, error: linkErr } = await supabase.auth.admin.generateLink({\n    type:  \'magiclink\',\n    email: internalEmail,\n  });\n  if (linkErr) throw new Error(`generateLink failed: ${linkErr.message}`);\n\n  // Step 4 — exchange hashed_token for real JWT session.\n  const { data: sessionData, error: sessionErr } = await supabase.auth.verifyOtp({\n    token_hash: linkData.properties.hashed_token,\n    type:       \'email\',\n  });\n  if (sessionErr) throw new Error(`verifyOtp failed: ${sessionErr.message}`);\n\n  return {\n    access_token:  sessionData.session.access_token,\n    refresh_token: sessionData.session.refresh_token,\n  };\n}\n\n// ---------------------------------------------------------------------------\n// POST /send-otp\n// ---------------------------------------------------------------------------\nrouter.post(\'/send-otp\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone } = req.body;\n\n  if (!phone || !PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n  const cleanPhone = phone.trim();\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) {\n    return res.status(404).json({\n      error:  \'No account found for this number. Please check your invite.\',\n      reason: \'phone_not_found\',\n    });\n  }\n\n  const { data: coupleRow } = await supabase\n    .from(\'couples\').select(\'id\').eq(\'user_id\', userRow.id).maybeSingle();\n  if (!coupleRow) {\n    return res.status(403).json({\n      error:  \'This number is registered as a Maker account, not a Dreamer.\',\n      reason: \'wrong_role\',\n    });\n  }\n\n  const otp     = generateOtp();\n  const otpHash = await bcrypt.hash(otp, BCRYPT_ROUNDS);\n  const expires = new Date(Date.now() + OTP_TTL_MS).toISOString();\n\n  const { error: upsertErr } = await supabase.from(\'otp_sessions\').upsert(\n    { phone: cleanPhone, otp_hash: otpHash, purpose: \'login\', expires_at: expires, created_at: new Date().toISOString() },\n    { onConflict: \'phone\' }\n  );\n  if (upsertErr) {\n    console.error(\'[couple:send-otp] upsert error:\', upsertErr.message);\n    return res.status(500).json({ error: \'Something went wrong. Please try again.\' });\n  }\n\n  try {\n    await getTwilio().messages.create({\n      from: `whatsapp:${BRIDE_WA}`,\n      to:   `whatsapp:${cleanPhone}`,\n      body: `Your Dream Wedding login code is: ${otp}. Valid for 5 minutes. Do not share this code.`,\n    });\n  } catch (err) {\n    console.error(\'[couple:send-otp] twilio error:\', err.message);\n    await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n    return res.status(500).json({ error: \'Could not send WhatsApp message. Please try again.\' });\n  }\n\n  console.log(`[couple:send-otp] sent to ${cleanPhone}`);\n  return res.json({ ok: true });\n});\n\n// ---------------------------------------------------------------------------\n// POST /forgot-pin\n// ---------------------------------------------------------------------------\nrouter.post(\'/forgot-pin\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone } = req.body;\n\n  if (!phone || !PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n  const cleanPhone = phone.trim();\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) {\n    return res.status(404).json({ error: \'No account found for this number.\', reason: \'phone_not_found\' });\n  }\n\n  const { data: coupleRow } = await supabase\n    .from(\'couples\').select(\'id\').eq(\'user_id\', userRow.id).maybeSingle();\n  if (!coupleRow) {\n    return res.status(403).json({ error: \'This number is not a Dreamer account.\', reason: \'wrong_role\' });\n  }\n\n  const otp     = generateOtp();\n  const otpHash = await bcrypt.hash(otp, BCRYPT_ROUNDS);\n  const expires = new Date(Date.now() + OTP_TTL_MS).toISOString();\n\n  const { error: upsertErr } = await supabase.from(\'otp_sessions\').upsert(\n    { phone: cleanPhone, otp_hash: otpHash, purpose: \'reset\', expires_at: expires, created_at: new Date().toISOString() },\n    { onConflict: \'phone\' }\n  );\n  if (upsertErr) {\n    console.error(\'[couple:forgot-pin] upsert error:\', upsertErr.message);\n    return res.status(500).json({ error: \'Something went wrong. Please try again.\' });\n  }\n\n  try {\n    await getTwilio().messages.create({\n      from: `whatsapp:${BRIDE_WA}`,\n      to:   `whatsapp:${cleanPhone}`,\n      body: `Your Dream Wedding PIN reset code is: ${otp}. Valid for 5 minutes. Do not share this code.`,\n    });\n  } catch (err) {\n    console.error(\'[couple:forgot-pin] twilio error:\', err.message);\n    await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n    return res.status(500).json({ error: \'Could not send WhatsApp message. Please try again.\' });\n  }\n\n  console.log(`[couple:forgot-pin] reset OTP sent to ${cleanPhone}`);\n  return res.json({ ok: true });\n});\n\n// ---------------------------------------------------------------------------\n// POST /verify-otp\n// Body:    { phone, otp, purpose }\n// Returns: { ok, user_id, couple_id, pin_set, access_token, refresh_token }\n// ---------------------------------------------------------------------------\nrouter.post(\'/verify-otp\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone, otp, purpose } = req.body;\n\n  if (!phone || !otp || !purpose) {\n    return res.status(400).json({ error: \'phone, otp and purpose are required.\' });\n  }\n  if (![\'login\', \'reset\'].includes(purpose)) {\n    return res.status(400).json({ error: \'purpose must be login or reset.\' });\n  }\n  if (!PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n\n  const cleanPhone = phone.trim();\n  const cleanOtp   = String(otp).trim();\n\n  const { data: otpRow } = await supabase\n    .from(\'otp_sessions\').select(\'otp_hash, purpose, expires_at\')\n    .eq(\'phone\', cleanPhone).maybeSingle();\n\n  if (!otpRow) {\n    return res.status(400).json({ error: \'No OTP found. Please request a new one.\', reason: \'otp_not_found\' });\n  }\n  if (new Date(otpRow.expires_at) < new Date()) {\n    await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n    return res.status(400).json({ error: \'OTP has expired. Please request a new one.\', reason: \'otp_expired\' });\n  }\n  if (otpRow.purpose !== purpose) {\n    return res.status(400).json({ error: \'OTP purpose mismatch.\', reason: \'otp_purpose_mismatch\' });\n  }\n\n  const valid = await bcrypt.compare(cleanOtp, otpRow.otp_hash);\n  if (!valid) {\n    return res.status(400).json({ error: \'Incorrect code. Please try again.\', reason: \'otp_invalid\' });\n  }\n\n  await supabase.from(\'otp_sessions\').delete().eq(\'phone\', cleanPhone);\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) return res.status(500).json({ error: \'Account not found after OTP verification.\' });\n\n  const { data: coupleRow } = await supabase\n    .from(\'couples\').select(\'id, pin_hash, pin_failed_attempts, pin_locked_until, users!inner(name)\')\n    .eq(\'user_id\', userRow.id).maybeSingle();\n  if (!coupleRow) return res.status(500).json({ error: \'Couple record not found after OTP verification.\' });\n\n  if (purpose === \'reset\' && (coupleRow.pin_failed_attempts > 0 || coupleRow.pin_locked_until)) {\n    await supabase.from(\'couples\')\n      .update({ pin_failed_attempts: 0, pin_locked_until: null })\n      .eq(\'id\', coupleRow.id);\n  }\n\n  let tokens;\n  try {\n    tokens = await mintSession(supabase, userRow.id);\n  } catch (err) {\n    console.error(\'[couple:verify-otp] mint error:\', err.message);\n    return res.status(500).json({ error: \'Could not create session. Please try again.\' });\n  }\n\n  const pinSet = !!coupleRow.pin_hash;\n  console.log(`[couple:verify-otp] ok phone=${cleanPhone} purpose=${purpose} pin_set=${pinSet}`);\n  return res.json({\n    ok:            true,\n    user_id:       userRow.id,\n    couple_id:     coupleRow.id,\n    pin_set:       pinSet,\n    name:          coupleRow.users?.name || null,\n    access_token:  tokens.access_token,\n    refresh_token: tokens.refresh_token,\n  });\n});\n\n// ---------------------------------------------------------------------------\n// POST /set-pin\n// Body: { couple_id, pin }\n// No auth — called immediately after verify-otp (phone already proved).\n// ---------------------------------------------------------------------------\nrouter.post(\'/set-pin\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { couple_id, pin } = req.body;\n\n  if (!couple_id || !pin) {\n    return res.status(400).json({ error: \'couple_id and pin are required.\' });\n  }\n  if (!PIN_RE.test(pin)) {\n    return res.status(400).json({ error: \'PIN must be exactly 4 digits.\' });\n  }\n\n  const pinHash = await bcrypt.hash(pin, BCRYPT_ROUNDS);\n  const { error } = await supabase.from(\'couples\')\n    .update({ pin_hash: pinHash, pin_failed_attempts: 0, pin_locked_until: null })\n    .eq(\'id\', couple_id);\n\n  if (error) {\n    console.error(\'[couple:set-pin] error:\', error.message);\n    return res.status(500).json({ error: \'Something went wrong. Please try again.\' });\n  }\n\n  console.log(`[couple:set-pin] PIN set couple_id=${couple_id}`);\n  return res.json({ ok: true });\n});\n\n// ---------------------------------------------------------------------------\n// POST /pin-login\n// Body:    { phone, pin }\n// Returns: { ok, user_id, couple_id, access_token, refresh_token }\n// ---------------------------------------------------------------------------\nrouter.post(\'/pin-login\', async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { phone, pin } = req.body;\n\n  if (!phone || !pin) {\n    return res.status(400).json({ error: \'phone and pin are required.\' });\n  }\n  if (!PHONE_RE.test(phone.trim())) {\n    return res.status(400).json({ error: \'Valid E.164 phone number required.\' });\n  }\n  if (!PIN_RE.test(pin)) {\n    return res.status(400).json({ error: \'PIN must be exactly 4 digits.\' });\n  }\n\n  const cleanPhone = phone.trim();\n\n  const { data: userRow } = await supabase\n    .from(\'users\').select(\'id\').eq(\'phone\', cleanPhone).maybeSingle();\n  if (!userRow) {\n    return res.status(404).json({ error: \'No account found for this number.\', reason: \'phone_not_found\' });\n  }\n\n  const { data: coupleRow } = await supabase\n    .from(\'couples\').select(\'id, pin_hash, pin_failed_attempts, pin_locked_until\')\n    .eq(\'user_id\', userRow.id).maybeSingle();\n  if (!coupleRow) {\n    return res.status(403).json({ error: \'This number is not a Dreamer account.\', reason: \'wrong_role\' });\n  }\n  if (!coupleRow.pin_hash) {\n    return res.status(400).json({ error: \'PIN not set yet. Please sign in with OTP first.\', reason: \'pin_not_set\' });\n  }\n\n  if (coupleRow.pin_locked_until && new Date(coupleRow.pin_locked_until) > new Date()) {\n    const mins = Math.ceil((new Date(coupleRow.pin_locked_until) - Date.now()) / 60000);\n    return res.status(429).json({\n      error:        `Too many incorrect attempts. Try again in ${mins} minute${mins === 1 ? \'\' : \'s\'}, or use Forgot PIN.`,\n      reason:       \'pin_locked\',\n      locked_until: coupleRow.pin_locked_until,\n    });\n  }\n\n  const valid = await bcrypt.compare(pin, coupleRow.pin_hash);\n\n  if (!valid) {\n    const attempts = (coupleRow.pin_failed_attempts || 0) + 1;\n    const update   = { pin_failed_attempts: attempts };\n    if (attempts >= LOCKOUT_ATTEMPTS) {\n      update.pin_locked_until    = new Date(Date.now() + LOCKOUT_MS).toISOString();\n      update.pin_failed_attempts = 0;\n    }\n    await supabase.from(\'couples\').update(update).eq(\'id\', coupleRow.id);\n    const left = LOCKOUT_ATTEMPTS - attempts;\n    console.log(`[couple:pin-login] wrong PIN phone=${cleanPhone} attempts=${attempts}`);\n    if (attempts >= LOCKOUT_ATTEMPTS) {\n      return res.status(429).json({ error: \'Too many incorrect attempts. Locked out for 15 minutes. Use Forgot PIN.\', reason: \'pin_locked\' });\n    }\n    return res.status(400).json({\n      error:              `Incorrect PIN. ${left} attempt${left === 1 ? \'\' : \'s\'} remaining.`,\n      reason:             \'pin_invalid\',\n      attempts_remaining: left,\n    });\n  }\n\n  await supabase.from(\'couples\')\n    .update({ pin_failed_attempts: 0, pin_locked_until: null })\n    .eq(\'id\', coupleRow.id);\n\n  let tokens;\n  try {\n    tokens = await mintSession(supabase, userRow.id);\n  } catch (err) {\n    console.error(\'[couple:pin-login] mint error:\', err.message);\n    return res.status(500).json({ error: \'Could not create session. Please try again.\' });\n  }\n\n  console.log(`[couple:pin-login] ok phone=${cleanPhone} couple_id=${coupleRow.id}`);\n  return res.json({\n    ok:            true,\n    user_id:       userRow.id,\n    couple_id:     coupleRow.id,\n    access_token:  tokens.access_token,\n    refresh_token: tokens.refresh_token,\n  });\n});\n\nmodule.exports = router;\n', 'src/api/admin/photos.js': "// src/api/admin/photos.js\n// Photo approval queue.\n'use strict';\n\nconst express      = require('express');\nconst router       = express.Router();\nconst requireAdmin = require('./requireAdmin');\nconst asyncHandler = require('../../lib/asyncHandler');\nconst { ok: okRes, err: errRes } = require('../../lib/response');\n\n// GET /queue — supports ?category=photographer&state=pending|approved|rejected|all&vendor_id=\nrouter.get('/queue', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const vendorId = req.query.vendor_id || null;\n  const category = req.query.category  || null;\n  const state    = req.query.state     || 'pending';\n  const validStates = ['pending', 'approved', 'rejected', 'all'];\n  if (!validStates.includes(state)) return errRes(res, 400, `state must be one of: ${validStates.join(', ')}.`);\n\n  let q = supabase.from('vendor_portfolio')\n    .select('id, vendor_id, image_url, caption, aesthetic_tags, approval_state, created_at, vendor:vendors(id, business_name, category, routing_handle, user:users(name))')\n    .order('created_at', { ascending: true });\n\n  if (state !== 'all') q = q.eq('approval_state', state);\n  if (vendorId) q = q.eq('vendor_id', vendorId);\n  if (category) q = q.eq('vendor.category', category);\n\n  const { data, error } = await q;\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { photos: data || [], total: (data || []).length });\n}));\n\n// POST /:imageId/approve\nrouter.post('/:imageId/approve', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { error } = await supabase.from('vendor_portfolio')\n    .update({ approval_state: 'approved', reviewed_by_admin: 'admin', reviewed_at: new Date().toISOString() })\n    .eq('id', req.params.imageId);\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, {});\n}));\n\n// POST /:imageId/reject\nrouter.post('/:imageId/reject', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const reason   = (req.body || {}).reason || null;\n  const { error } = await supabase.from('vendor_portfolio')\n    .update({ approval_state: 'rejected', reviewed_by_admin: 'admin', reviewed_at: new Date().toISOString(), rejection_reason: reason })\n    .eq('id', req.params.imageId);\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, {});\n}));\n\n// POST /bulk-approve\nrouter.post('/bulk-approve', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase  = req.app.locals.supabase;\n  const imageIds  = (req.body || {}).image_ids || [];\n  if (!imageIds.length) return errRes(res, 400, 'image_ids required.');\n  const { error } = await supabase.from('vendor_portfolio')\n    .update({ approval_state: 'approved', reviewed_by_admin: 'admin', reviewed_at: new Date().toISOString() })\n    .in('id', imageIds);\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { approved: imageIds.length });\n}));\n\nmodule.exports = router;\n", 'src/api/admin/vendors.js': '// src/api/admin/vendors.js\n// Admin vendor management — list, create, tier, approve, discover-eligible.\n\'use strict\';\n\nconst express      = require(\'express\');\nconst router       = express.Router();\nconst requireAdmin = require(\'./requireAdmin\');\nconst asyncHandler = require(\'../../lib/asyncHandler\');\nconst { ok: okRes, err: errRes } = require(\'../../lib/response\');\n\nconst VALID_TIERS = [\'trial\', \'essential\', \'signature\', \'prestige\'];\n\n// ─── GET /api/v2/admin/vendors ──────────────────────────────────────────\nrouter.get(\'/\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n\n  const { data, error } = await supabase\n    .from(\'vendors\')\n    .select(`\n      id, business_name, category, city, tier, status, founding_cohort,\n      discover_eligible, discover_request_state, created_at,\n      users!inner(name, phone)\n    `)\n    .order(\'created_at\', { ascending: false });\n\n  if (error) return errRes(res, 500, error.message);\n\n  const vendors = (data || []).map(v => ({\n    id:                    v.id,\n    name:                  v.business_name || v.users?.name || \'Unnamed\',\n    category:              v.category,\n    city:                  v.city,\n    phone:                 v.users?.phone,\n    tier:                  v.tier,\n    status:                v.status,\n    founding_cohort:       v.founding_cohort || false,\n    discover_eligible:     v.discover_eligible || false,\n    discover_request_state: v.discover_request_state || \'not_requested\',\n    created_at:            v.created_at,\n  }));\n\n  return okRes(res, { vendors, total: vendors.length });\n}));\n\n// ─── POST /api/v2/admin/vendors/create ──────────────────────────────────\nrouter.post(\'/create\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { business_name, phone, category, city, tier } = req.body;\n\n  if (!phone) return errRes(res, 400, \'phone is required.\');\n\n  // Create user + vendor via existing RPC (same as HTML admin invite flow).\n  const { error: rpcError } = await supabase.rpc(\'invite_vendor\', {\n    p_phone: phone.trim(),\n    p_name:  business_name?.trim() || \'Vendor\',\n  });\n  if (rpcError) return errRes(res, 400, rpcError.message);\n\n  // Patch additional fields supplied by admin form.\n  const { data: user } = await supabase\n    .from(\'users\')\n    .select(\'id\')\n    .eq(\'phone\', phone.trim())\n    .single();\n\n  if (user) {\n    const patch = {};\n    if (business_name) patch.business_name = business_name.trim();\n    if (category)      patch.category      = category;\n    if (city)          patch.city          = city;\n    if (tier && VALID_TIERS.includes(tier)) patch.tier = tier;\n\n    if (Object.keys(patch).length) {\n      await supabase.from(\'vendors\').update(patch).eq(\'user_id\', user.id);\n    }\n  }\n\n  return okRes(res, { created: true });\n}));\n\n// ─── PATCH /api/v2/admin/vendors/:id/tier ───────────────────────────────\nrouter.patch(\'/:vendorId/tier\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { tier } = req.body;\n\n  if (!VALID_TIERS.includes(tier)) return errRes(res, 400, `Invalid tier. Must be one of: ${VALID_TIERS.join(\', \')}.`);\n\n  const { error } = await supabase\n    .from(\'vendors\')\n    .update({ tier })\n    .eq(\'id\', req.params.vendorId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { tier });\n}));\n\n// ─── PATCH /api/v2/admin/vendors/:id/approve ────────────────────────────\nrouter.patch(\'/:vendorId/approve\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n\n  // Toggle status: active <-> paused. "Approve" sets active, re-approving toggles.\n  const { data: vendor, error: fetchErr } = await supabase\n    .from(\'vendors\')\n    .select(\'status\')\n    .eq(\'id\', req.params.vendorId)\n    .single();\n\n  if (fetchErr) return errRes(res, 404, \'Vendor not found.\');\n\n  const newStatus = vendor.status === \'active\' ? \'paused\' : \'active\';\n  const { error } = await supabase\n    .from(\'vendors\')\n    .update({ status: newStatus })\n    .eq(\'id\', req.params.vendorId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { status: newStatus });\n}));\n\n// ─── PATCH /api/v2/admin/vendors/:id/discover-eligible ──────────────────\nrouter.patch(\'/:vendorId/discover-eligible\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n\n  const { data: vendor, error: fetchErr } = await supabase\n    .from(\'vendors\')\n    .select(\'discover_eligible\')\n    .eq(\'id\', req.params.vendorId)\n    .single();\n\n  if (fetchErr) return errRes(res, 404, \'Vendor not found.\');\n\n  const newVal = !vendor.discover_eligible;\n  const { error } = await supabase\n    .from(\'vendors\')\n    .update({ discover_eligible: newVal })\n    .eq(\'id\', req.params.vendorId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { discover_eligible: newVal });\n}));\n\n// ─── PATCH /api/v2/admin/vendors/:id/dreamai ────────────────────────────\n// Toggle a vendor\'s DreamAi PWA access (briefing_enabled serves as the gate).\nrouter.patch(\'/:vendorId/dreamai\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { access } = req.body;\n\n  const { error } = await supabase\n    .from(\'vendors\')\n    .update({ briefing_enabled: !!access })\n    .eq(\'id\', req.params.vendorId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { dreamai_access: !!access });\n}));\n\n// ─── PATCH /api/v2/admin/vendors/:id/revoke ─────────────────────────────\nrouter.patch(\'/:vendorId/revoke\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n\n  const { error } = await supabase\n    .from(\'vendors\')\n    .update({ status: \'paused\', discover_eligible: false })\n    .eq(\'id\', req.params.vendorId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { revoked: true });\n}));\n\n// ── DELETE /api/v2/admin/vendors/:vendorId ────────────────────────────────────\n// Hard delete. Cascades to all vendor data via FK constraints.\n// Requires confirmation — caller must pass { confirm: true } in body.\nrouter.delete(\'/:vendorId\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  if (!req.body?.confirm) return errRes(res, 400, \'Pass { confirm: true } to confirm deletion.\');\n\n  // Delete the users row — cascades to vendors + all vendor data\n  const { data: vendor } = await supabase\n    .from(\'vendors\').select(\'user_id\').eq(\'id\', req.params.vendorId).maybeSingle();\n  if (!vendor) return errRes(res, 404, \'Vendor not found.\');\n\n  const { error } = await supabase.from(\'users\').delete().eq(\'id\', vendor.user_id);\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { deleted: true });\n}));\n\nmodule.exports = router;\n', 'src/api/admin/couples.js': '// src/api/admin/couples.js\n// Admin couple management — list, create, tier, revoke.\n\'use strict\';\n\nconst express      = require(\'express\');\nconst router       = express.Router();\nconst requireAdmin = require(\'./requireAdmin\');\nconst asyncHandler = require(\'../../lib/asyncHandler\');\nconst { ok: okRes, err: errRes } = require(\'../../lib/response\');\n\nconst VALID_TIERS = [\'basic\', \'gold\', \'platinum\'];\n\n// ─── GET /api/v2/admin/couples ──────────────────────────────────────────\nrouter.get(\'/\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n\n  const { data, error } = await supabase\n    .from(\'couples\')\n    .select(`\n      id, wedding_date, wedding_city, planning_state, created_at,\n      users!inner(name, phone)\n    `)\n    .order(\'created_at\', { ascending: false });\n\n  if (error) return errRes(res, 500, error.message);\n\n  const coupleIds = (data || []).map(c => c.id);\n\n  // Counts in parallel — muse saves + circle members.\n  const [museSavesRes, circleMembersRes] = await Promise.all([\n    supabase\n      .from(\'muse_saves\')\n      .select(\'couple_id\')\n      .in(\'couple_id\', coupleIds),\n    supabase\n      .from(\'circle_members\')\n      .select(\'couple_id, status\')\n      .in(\'couple_id\', coupleIds)\n      .eq(\'status\', \'active\'),\n  ]);\n\n  const museCounts   = {};\n  const circleCounts = {};\n  for (const row of (museSavesRes.data || []))   museCounts[row.couple_id]   = (museCounts[row.couple_id]   || 0) + 1;\n  for (const row of (circleMembersRes.data || [])) circleCounts[row.couple_id] = (circleCounts[row.couple_id] || 0) + 1;\n\n  const couples = (data || []).map(c => ({\n    id:              c.id,\n    name:            c.users?.name || \'Unknown\',\n    phone:           c.users?.phone,\n    wedding_date:    c.wedding_date,\n    wedding_city:    c.wedding_city,\n    planning_state:  c.planning_state,\n    muse_saves:      museCounts[c.id]   || 0,\n    circle_members:  circleCounts[c.id] || 0,\n    created_at:      c.created_at,\n  }));\n\n  return okRes(res, { couples, total: couples.length });\n}));\n\n// ─── POST /api/v2/admin/couples/create ──────────────────────────────────\nrouter.post(\'/create\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { name, phone } = req.body;\n\n  if (!phone || !name) return errRes(res, 400, \'name and phone are required.\');\n\n  // Upsert user row.\n  const { data: user, error: userErr } = await supabase\n    .from(\'users\')\n    .upsert({ phone: phone.trim(), name: name.trim() }, { onConflict: \'phone\' })\n    .select(\'id\')\n    .single();\n\n  if (userErr) return errRes(res, 400, userErr.message);\n\n  // Insert couple row.\n  const { error: coupleErr } = await supabase\n    .from(\'couples\')\n    .insert({ user_id: user.id, planning_state: \'browsing\' });\n\n  if (coupleErr) return errRes(res, 400, coupleErr.message);\n\n  return okRes(res, { created: true });\n}));\n\n// ─── PATCH /api/v2/admin/couples/:id/tier ───────────────────────────────\n// Couples don\'t have a tier column yet — placeholder for when it\'s added.\nrouter.patch(\'/:coupleId/tier\', requireAdmin, asyncHandler(async (req, res) => {\n  const { tier } = req.body;\n  if (!VALID_TIERS.includes(tier)) return errRes(res, 400, `Invalid tier. Must be one of: ${VALID_TIERS.join(\', \')}.`);\n  // No tier column on couples yet — return ok so the admin UI doesn\'t error.\n  return okRes(res, { tier, note: \'Couple tiers not yet enforced in DB.\' });\n}));\n\n// ─── PATCH /api/v2/admin/couples/:id/revoke ─────────────────────────────\n// "Revoke" for couples means deleting their circle + muse data and resetting planning state.\nrouter.patch(\'/:coupleId/revoke\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n\n  const { error } = await supabase\n    .from(\'couples\')\n    .update({ planning_state: \'browsing\' })\n    .eq(\'id\', req.params.coupleId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { revoked: true });\n}));\n\n// ── DELETE /api/v2/admin/couples/:coupleId ────────────────────────────────────\n// Hard delete. Cascades to all couple data via FK constraints.\nrouter.delete(\'/:coupleId\', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  if (!req.body?.confirm) return errRes(res, 400, \'Pass { confirm: true } to confirm deletion.\');\n\n  const { data: couple } = await supabase\n    .from(\'couples\').select(\'user_id\').eq(\'id\', req.params.coupleId).maybeSingle();\n  if (!couple) return errRes(res, 404, \'Couple not found.\');\n\n  const { error } = await supabase.from(\'users\').delete().eq(\'id\', couple.user_id);\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { deleted: true });\n}));\n\nmodule.exports = router;\n', 'src/api/admin/vendorPortfolio.js': "// src/api/admin/vendorPortfolio.js\n// Admin-side vendor portfolio management.\n// Allows admin to upload photos directly to any vendor's portfolio,\n// bypassing the approval queue (admin uploads are auto-approved).\n//\n// GET  /api/v2/admin/vendors/:vendorId/portfolio       — list photos\n// POST /api/v2/admin/vendors/:vendorId/portfolio/upload-url — get signed Cloudinary params\n// POST /api/v2/admin/vendors/:vendorId/portfolio       — register uploaded photo\n// DELETE /api/v2/admin/vendors/:vendorId/portfolio/:imageId — delete photo\n'use strict';\n\nconst express      = require('express');\nconst router       = express.Router({ mergeParams: true });\nconst requireAdmin = require('./requireAdmin');\nconst asyncHandler = require('../../lib/asyncHandler');\nconst { ok: okRes, err: errRes } = require('../../lib/response');\nconst { generateUploadParams, deleteFromCloudinary } = require('../../lib/vendor/portfolio');\n\n// ── GET /:vendorId/portfolio ──────────────────────────────────────────────────\nrouter.get('/', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase  = req.app.locals.supabase;\n  const vendorId  = req.params.vendorId;\n\n  const { data: vendor } = await supabase\n    .from('vendors').select('id').eq('id', vendorId).maybeSingle();\n  if (!vendor) return errRes(res, 404, 'Vendor not found.');\n\n  const { data, error } = await supabase\n    .from('vendor_portfolio')\n    .select('id, image_url, caption, aesthetic_tags, is_hero, in_carousel, approval_state, created_at')\n    .eq('vendor_id', vendorId)\n    .order('created_at', { ascending: false });\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { photos: data || [] });\n}));\n\n// ── POST /:vendorId/portfolio/upload-url ──────────────────────────────────────\nrouter.post('/upload-url', requireAdmin, asyncHandler(async (req, res) => {\n  const vendorId = req.params.vendorId;\n  const filename = req.body.filename || 'photo.jpg';\n\n  const { upload_url, params } = generateUploadParams(vendorId, filename);\n  return okRes(res, { upload_url, params });\n}));\n\n// ── POST /:vendorId/portfolio ─────────────────────────────────────────────────\n// Register a photo. Admin uploads are auto-approved.\nrouter.post('/', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const vendorId = req.params.vendorId;\n  const { image_url, caption, aesthetic_tags, is_hero } = req.body;\n\n  if (!image_url) return errRes(res, 400, 'image_url is required.');\n\n  const { data: vendor } = await supabase\n    .from('vendors').select('id').eq('id', vendorId).maybeSingle();\n  if (!vendor) return errRes(res, 404, 'Vendor not found.');\n\n  // If setting as hero, unset existing hero first\n  if (is_hero) {\n    await supabase.from('vendor_portfolio')\n      .update({ is_hero: false }).eq('vendor_id', vendorId);\n  }\n\n  const { data, error } = await supabase\n    .from('vendor_portfolio')\n    .insert({\n      vendor_id:      vendorId,\n      image_url,\n      caption:        caption || null,\n      aesthetic_tags: aesthetic_tags || [],\n      is_hero:        is_hero || false,\n      in_carousel:    true,\n      approval_state: 'approved',   // admin uploads skip the queue\n      reviewed_by_admin: 'admin',\n      reviewed_at:    new Date().toISOString(),\n    })\n    .select()\n    .single();\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { photo: data });\n}));\n\n// ── DELETE /:vendorId/portfolio/:imageId ──────────────────────────────────────\nrouter.delete('/:imageId', requireAdmin, asyncHandler(async (req, res) => {\n  const supabase = req.app.locals.supabase;\n  const { vendorId, imageId } = req.params;\n\n  const { data: photo } = await supabase\n    .from('vendor_portfolio')\n    .select('id, image_url, vendor_id')\n    .eq('id', imageId)\n    .eq('vendor_id', vendorId)\n    .maybeSingle();\n\n  if (!photo) return errRes(res, 404, 'Photo not found.');\n\n  await deleteFromCloudinary(photo.image_url);\n\n  const { error } = await supabase\n    .from('vendor_portfolio').delete().eq('id', imageId);\n\n  if (error) return errRes(res, 500, error.message);\n  return okRes(res, { deleted: true });\n}));\n\nmodule.exports = router;\n", 'src/api/router.js': "// src/api/router.js\n// Top-level /api/v2 router.\n// Mounted in src/index.js as: app.use('/api/v2', require('./api/router'));\n\n'use strict';\n\nconst express          = require('express');\nconst router           = express.Router();\n\nconst waitlistRouter        = require('./waitlist');\nconst inviteRouter          = require('./invite');\nconst vendorAuthRouter      = require('./vendor/auth');\nconst coupleAuthRouter      = require('./couple/auth');\nconst pinStatusRouter       = require('./pin-status');\nconst landingSlidesRouter   = require('./landing-slides');\nconst exploringPhotosRouter = require('./exploring-photos');\nconst testRouter            = require('./_test/whoami');\n\nrouter.use('/waitlist',           waitlistRouter);\nrouter.use('/invite',             inviteRouter);\nrouter.use('/vendor/auth',        vendorAuthRouter);\nrouter.use('/couple/auth',        coupleAuthRouter);\nrouter.use('/auth/pin-status',    pinStatusRouter);\nrouter.use('/landing-slides',     landingSlidesRouter);\nrouter.use('/exploring-photos',   exploringPhotosRouter);\nrouter.use('/_test/whoami',       testRouter);\nrouter.use('/hot-dates',          require('./public/hotDates'));\nrouter.use('/vendor',             require('./vendor/core'));\nrouter.use('/admin/discover',        require('./admin/discover'));\nrouter.use('/admin/photos',          require('./admin/photos'));\nrouter.use('/admin/couture',         require('./admin/couture'));\nrouter.use('/admin/featured',        require('./admin/featured'));\nrouter.use('/admin/vendors',         require('./admin/vendors'));\nrouter.use('/admin/couples',         require('./admin/couples'));\nrouter.use('/admin/hot-dates',       require('./admin/hotDates'));\nrouter.use('/admin/invites',         require('./admin/invites'));\nrouter.use('/admin/config',          require('./admin/config'));\nrouter.use('/admin',                 require('./admin/content'));\nrouter.use('/admin/muse-pool',       require('./admin/musePool').adminRouter);\nrouter.use('/admin/surprise-pool',   require('./admin/surprisePool'));\nrouter.use('/admin/spotlight',       require('./admin/spotlight').adminRouter);\nrouter.use('/admin/discover-heroes', require('./admin/discoverHeroes').adminRouter);\nrouter.use('/admin/conversations',   require('./admin/conversations'));\nrouter.use('/admin/vendors/:vendorId/portfolio', require('./admin/vendorPortfolio'));\n// Public endpoints for content surfaces\nrouter.use('/muse-pool',             require('./admin/musePool').publicRouter);\nrouter.use('/spotlight',             require('./admin/spotlight').publicRouter);\nrouter.use('/discover-heroes',       require('./admin/discoverHeroes').publicRouter);\n\n// Couple routes — profile must be before /couple catch-all\nrouter.use('/discover',       require('./couple/discover'));\nconst requireCoupleAuth = require('./middleware/requireCoupleAuth');\nrouter.use('/couple/muse',    requireCoupleAuth, require('./couple/muse'));\nrouter.use('/couple/profile', require('./couple/profile'));          // public, before /couple catch-all\nrouter.use('/couple',         require('./couple/core'));\n\n// B-3a: circle member / coplanner endpoints\n// No requireCircleMemberAuth — coplanner sends no JWT. Each endpoint validates\n// via userId/memberUserId/brideId params against circle_members table directly.\nrouter.use('/auth/verify-pin',       require('./circle/verifyPin'));   // public\nrouter.use('/circle/session',        require('./circle/session'));      // public\nrouter.use('/frost/circle/feed',     require('./circle/feed'));         // brideId validates couple exists\nrouter.use('/circle/muse',           require('./circle/muse'));         // memberUserId validates circle_member\nrouter.use('/frost/circle/threads',  require('./circle/threads'));      // brideId scopes conversations\nrouter.use('/frost/circle/messages', require('./circle/messages'));     // no per-user auth\nrouter.use('/dreamai',               require('./circle/dreamai'));      // user_id + primary_user_id validate\n\nmodule.exports = router;\n"}
